    "environment": "dev",
    "method": "FEParamGetCondicionIvaReceptor",
    "wsid": "wsfe",
    "params": {
        "Auth" : { 
            "Token": "{{token}}",
            "Sign": "{{sign}}",
            "Cuit": "{{cuit]]"
        }
    }
}
```
